// pages/index.jsx — Page de connexion ReMine avec stats réelles
import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';
import { dashboardAPI } from '../services/api';

const LOGO = "data:image/png;base64,";
const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5001/api';

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPwd, setShowPwd] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [apiOk, setApiOk] = useState(null);
  const [checking, setChecking] = useState(true);
  const [stats, setStats] = useState({
    totalReports: '...', resolutionRate: '...', totalUsers: '...', topLocation: '...'
  });

  useEffect(() => {
    const token = localStorage.getItem('remine_admin_token');
    if (token) { router.push('/dashboard'); return; }
    setChecking(false);

    // Health check
    dashboardAPI.healthCheck()
      .then(r => setApiOk(r.success !== false))
      .catch(() => setApiOk(false));

    // Stats publiques réelles
    fetch(`${API_BASE}/public/stats`)
      .then(r => r.json())
      .then(data => {
        if (data.success) {
          setStats({
            totalReports: data.data.totalReports + '+',
            resolutionRate: data.data.resolutionRate + '%',
            totalUsers: data.data.totalUsers,
            topLocation: data.data.topLocation || 'Sénégal',
          });
        }
      })
      .catch(() => {});
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const result = await dashboardAPI.login(email, password);
      if (result.success) {
        const role = result.data?.user?.role;
        if (!['admin', 'moderator'].includes(role)) {
          setError('Accès réservé aux administrateurs.');
          dashboardAPI.logout();
          setLoading(false);
          return;
        }
        const token = result.data?.token || localStorage.getItem('remine_admin_token');
        if (token) {
          document.cookie = `remine_token=${token}; path=/; max-age=604800; SameSite=Lax`;
        }
        router.push('/dashboard');
      } else {
        setError(result.error || 'Email ou mot de passe incorrect');
      }
    } catch {
      setError('Impossible de se connecter au serveur.');
    } finally {
      setLoading(false);
    }
  };

  if (checking) return null;

  const statCards = [
    { v: stats.totalReports, l: 'Signalements' },
    { v: stats.resolutionRate, l: 'Taux résolution' },
    { v: stats.totalUsers, l: 'Citoyens inscrits' },
    { v: stats.topLocation, l: 'Zone principale' },
  ];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
        * { margin:0; padding:0; box-sizing:border-box; }
        body { font-family:'DM Sans',sans-serif; background:#061209; color:#fff; min-height:100vh; }

        .page { min-height:100vh; display:grid; grid-template-columns:1fr 1fr; }
        @media(max-width:768px){ .page{grid-template-columns:1fr;} .left-panel{display:none;} }

        .left-panel {
          background:linear-gradient(160deg,#07200f 0%,#041009 100%);
          padding:56px 48px;
          display:flex; flex-direction:column; justify-content:space-between;
          position:relative; overflow:hidden;
        }
        .left-panel::before {
          content:''; position:absolute; top:-120px; left:-120px;
          width:480px; height:480px; border-radius:50%;
          background:radial-gradient(circle,rgba(45,212,96,0.12) 0%,transparent 65%);
          pointer-events:none;
        }
        .left-panel::after {
          content:''; position:absolute; bottom:-100px; right:-80px;
          width:380px; height:380px; border-radius:50%;
          background:radial-gradient(circle,rgba(234,179,8,0.07) 0%,transparent 65%);
          pointer-events:none;
        }

        .brand { position:relative; z-index:1; }
        .brand-top { display:flex; align-items:center; gap:16px; margin-bottom:52px; }

        .logo-wrap {
          width:64px; height:64px; border-radius:18px; overflow:hidden;
          background:#fff; display:flex; align-items:center; justify-content:center;
          box-shadow:0 8px 32px rgba(0,0,0,0.4),0 0 0 1px rgba(255,255,255,0.1);
          flex-shrink:0;
        }
        .logo-wrap img { width:100%; height:100%; object-fit:cover; }

        .brand-name { font-family:'Syne',sans-serif; font-size:20px; font-weight:800; color:#fff; letter-spacing:-0.3px; }
        .brand-sub { font-size:11px; color:rgba(255,255,255,0.4); letter-spacing:2.5px; text-transform:uppercase; margin-top:2px; }

        .hero-title { font-family:'Syne',sans-serif; font-size:44px; font-weight:800; line-height:1.08; letter-spacing:-1.5px; color:#fff; margin-bottom:18px; }
        .hero-title .accent { color:#2dd460; }
        .hero-desc { font-size:15px; color:rgba(255,255,255,0.45); line-height:1.75; max-width:320px; }

        .stats-grid { display:grid; grid-template-columns:1fr 1fr; gap:10px; position:relative; z-index:1; }
        .stat-card { background:rgba(255,255,255,0.04); border:1px solid rgba(255,255,255,0.07); border-radius:16px; padding:18px 20px; }
        .stat-val { font-family:'Syne',sans-serif; font-size:26px; font-weight:800; color:#2dd460; margin-bottom:3px; }
        .stat-lbl { font-size:12px; color:rgba(255,255,255,0.35); }

        .right-panel {
          background:#0b1710; display:flex; align-items:center; justify-content:center;
          padding:40px 32px; position:relative;
        }
        .right-panel::before {
          content:''; position:absolute; inset:0;
          background:radial-gradient(ellipse at 15% 15%,rgba(45,212,96,0.05) 0%,transparent 45%),
                      radial-gradient(ellipse at 85% 85%,rgba(234,179,8,0.04) 0%,transparent 45%);
          pointer-events:none;
        }

        .form-wrap { width:100%; max-width:400px; position:relative; z-index:1; }

        .mobile-brand { display:none; align-items:center; gap:14px; margin-bottom:36px; }
        @media(max-width:768px){ .mobile-brand{display:flex;} }
        .mobile-logo { width:52px; height:52px; border-radius:14px; overflow:hidden; background:#fff; }
        .mobile-logo img { width:100%; height:100%; object-fit:cover; }
        .mobile-brand-name { font-family:'Syne',sans-serif; font-size:18px; font-weight:800; color:#fff; }
        .mobile-brand-sub { font-size:11px; color:#2dd460; letter-spacing:1.5px; text-transform:uppercase; }

        .form-tag {
          display:inline-flex; align-items:center; gap:6px;
          font-size:10px; font-weight:700; letter-spacing:2.5px; text-transform:uppercase;
          color:#2dd460; background:rgba(45,212,96,0.08); border:1px solid rgba(45,212,96,0.18);
          border-radius:30px; padding:5px 14px; margin-bottom:18px;
        }
        .form-tag::before {
          content:''; width:6px; height:6px; border-radius:50%; background:#2dd460;
          animation:pulse 2s infinite;
        }
        @keyframes pulse { 0%,100%{opacity:1;transform:scale(1);} 50%{opacity:0.5;transform:scale(0.8);} }

        .form-title { font-family:'Syne',sans-serif; font-size:32px; font-weight:800; color:#fff; letter-spacing:-1px; margin-bottom:6px; }
        .form-sub { font-size:14px; color:rgba(255,255,255,0.35); margin-bottom:32px; }

        .status { display:flex; align-items:center; gap:8px; padding:9px 14px; border-radius:10px; font-size:13px; margin-bottom:20px; }
        .status.ok { background:rgba(45,212,96,0.07); border:1px solid rgba(45,212,96,0.18); color:#4ade80; }
        .status.err { background:rgba(239,68,68,0.07); border:1px solid rgba(239,68,68,0.18); color:#f87171; }
        .dot { width:7px; height:7px; border-radius:50%; flex-shrink:0; }

        .err-box {
          background:rgba(239,68,68,0.07); border:1px solid rgba(239,68,68,0.18);
          border-radius:12px; padding:11px 15px; color:#f87171; font-size:13px;
          display:flex; align-items:center; gap:8px; margin-bottom:18px;
        }

        .field { margin-bottom:16px; }
        .field label { display:block; font-size:11px; font-weight:600; letter-spacing:1.5px; text-transform:uppercase; color:rgba(255,255,255,0.4); margin-bottom:7px; }
        .inp-wrap { position:relative; }
        .inp-wrap input {
          width:100%; background:rgba(255,255,255,0.04); border:1px solid rgba(255,255,255,0.07);
          border-radius:12px; padding:13px 16px; font-size:15px; color:#fff;
          font-family:'DM Sans',sans-serif; outline:none; transition:all 0.2s;
        }
        .inp-wrap input:focus { border-color:rgba(45,212,96,0.45); background:rgba(45,212,96,0.04); box-shadow:0 0 0 3px rgba(45,212,96,0.07); }
        .inp-wrap input::placeholder { color:rgba(255,255,255,0.18); }
        .toggle { position:absolute; right:13px; top:50%; transform:translateY(-50%); background:none; border:none; color:rgba(255,255,255,0.25); cursor:pointer; font-size:15px; padding:4px; transition:color 0.2s; }
        .toggle:hover { color:rgba(255,255,255,0.55); }

        .btn {
          width:100%; margin-top:10px; padding:14px;
          background:linear-gradient(135deg,#2dd460,#16a34a);
          color:#fff; border:none; border-radius:12px;
          font-size:15px; font-weight:700; font-family:'Syne',sans-serif;
          letter-spacing:0.2px; cursor:pointer; transition:all 0.2s;
          box-shadow:0 4px 24px rgba(45,212,96,0.22);
        }
        .btn:not(:disabled):hover { transform:translateY(-1px); box-shadow:0 8px 32px rgba(45,212,96,0.32); }
        .btn:disabled { opacity:0.65; cursor:not-allowed; }

        .divider { height:1px; background:rgba(255,255,255,0.06); margin:24px 0; }
        .footer { text-align:center; font-size:11px; color:rgba(255,255,255,0.18); margin-top:16px; letter-spacing:0.3px; }
        .senegal-badge { display:flex; align-items:center; justify-content:center; gap:6px; font-size:12px; color:rgba(255,255,255,0.25); }
      `}</style>

      <div className="page">
        <div className="left-panel">
          <div className="brand">
            <div className="brand-top">
              <div className="logo-wrap"><img src={LOGO} alt="ReMine" /></div>
              <div>
                <div className="brand-name">ReMine</div>
                <div className="brand-sub">Citizen Track</div>
              </div>
            </div>
            <h2 className="hero-title">Tableau de bord<br /><span className="accent">administrateur</span></h2>
            <p className="hero-desc">Gérez les signalements environnementaux, analysez les données et coordonnez les interventions en temps réel au Sénégal.</p>
          </div>
          <div className="stats-grid">
            {statCards.map(s => (
              <div key={s.l} className="stat-card">
                <div className="stat-val">{s.v}</div>
                <div className="stat-lbl">{s.l}</div>
              </div>
            ))}
          </div>
        </div>

        <div className="right-panel">
          <div className="form-wrap">
            <div className="mobile-brand">
              <div className="mobile-logo"><img src={LOGO} alt="ReMine" /></div>
              <div>
                <div className="mobile-brand-name">ReMine</div>
                <div className="mobile-brand-sub">Citizen Track</div>
              </div>
            </div>

            <div className="form-tag">Admin Access</div>
            <h1 className="form-title">Connexion</h1>
            <p className="form-sub">Accédez à votre espace administrateur</p>

            {apiOk !== null && (
              <div className={`status ${apiOk ? 'ok' : 'err'}`}>
                <div className="dot" style={{ background: apiOk ? '#2dd460' : '#ef4444' }} />
                {apiOk ? 'Serveur connecté' : 'Serveur inaccessible'}
              </div>
            )}

            {error && <div className="err-box"><span>⚠️</span> {error}</div>}

            <form onSubmit={handleSubmit}>
              <div className="field">
                <label>Adresse email</label>
                <div className="inp-wrap">
                  <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="admin@remine.sn" required autoComplete="email" />
                </div>
              </div>
              <div className="field">
                <label>Mot de passe</label>
                <div className="inp-wrap">
                  <input type={showPwd ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" required autoComplete="current-password" style={{ paddingRight:'42px' }} />
                  <button type="button" className="toggle" onClick={() => setShowPwd(!showPwd)}>{showPwd ? '🙈' : '👁️'}</button>
                </div>
              </div>
              <button type="submit" className="btn" disabled={loading}>
                {loading ? '⏳ Connexion...' : '🚀 Se connecter'}
              </button>
            </form>

            <div className="divider" />
            <div className="senegal-badge">🇸🇳 Plateforme citoyenne — Sénégal</div>
            <p className="footer">ReMine Citizen Track v1.0 · Espace administrateur</p>
          </div>
        </div>
      </div>
    </>
  );
}